// ExecutePricingScript executes a Lua script that defines a calculate_final_price function.
// It passes the context map as a Lua table to that function and returns the result as a float64.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua VM
	L := lua.NewState()
	defer L.Close()

	// Register a global function to convert Go map to Lua table
	registerMapToTable(L, ctx)

	// Execute the user-provided script
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function from the global namespace
	luaFunc := L.GetGlobal("calculate_final_price")
	if luaFunc.Type() == lua.LTNil {
		return 0, fmt.Errorf("calculate_final_price function not found in script")
	}

	// Ensure it's a function
	if luaFunc.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function")
	}

	// Convert the context map to a Lua table
	ctxTable := mapToLuaTable(L, ctx)

	// Call the function with the context table as argument
	L.Push(luaFunc)
	L.Push(ctxTable)
	if err := L.PCall(1, 1, nil); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the result
	ret := L.Get(-1)
	L.Pop(1) // Remove the returned value from stack

	// Convert Lua number to Go float64
	if ret.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	return float64(ret.(lua.LNumber)), nil
}

// mapToLuaTable converts a Go map[string]float64 to a Lua table
func mapToLuaTable(L *lua.LState, m map[string]float64) *lua.LTable {
	table := L.NewTable()
	for k, v := range m {
		L.SetField(table, k, lua.LNumber(v))
	}
	return table
}

// registerMapToTable registers a global function that allows Lua code to access
// the context table (optional, but can be useful for debugging)
func registerMapToTable(L *lua.LState, ctx map[string]float64) {
	// This is optional but can be useful if the Lua script wants to access
	// the context through a global variable instead of the function parameter
	ctxTable := mapToLuaTable(L, ctx)
	L.SetGlobal("context", ctxTable)
}

